import { useCallback, useEffect, useMemo, useState } from "react";
import { normalizeError, resolvePodClient } from "./utils.js";
export function useFilePreview({ client, podId, path = null, enabled = true, autoLoad = true, mode = "rendered", artifact = "document.md", }) {
    const [content, setContent] = useState(null);
    const [blob, setBlob] = useState(null);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState(null);
    const trimmedPath = typeof path === "string" ? path.trim() : "";
    const isEnabled = enabled && trimmedPath.length > 0;
    const refresh = useCallback(async (overrides = {}, signal) => {
        const nextPath = typeof overrides.path === "string" ? overrides.path.trim() : trimmedPath;
        const nextMode = overrides.mode ?? mode;
        const nextArtifact = overrides.artifact ?? artifact;
        if (!enabled || nextPath.length === 0) {
            setContent(null);
            setBlob(null);
            setError(null);
            setIsLoading(false);
            return null;
        }
        setIsLoading(true);
        setError(null);
        try {
            const scopedClient = resolvePodClient(client, podId);
            if (nextMode === "artifact") {
                const childPath = nextArtifact ? `${nextPath}/${nextArtifact}` : nextPath;
                const nextBlob = await scopedClient.files.children.content(childPath);
                const text = await nextBlob.text();
                if (signal?.aborted)
                    return null;
                setBlob(nextBlob);
                setContent(text);
                return text;
            }
            const renderedBlob = await scopedClient.files.children.markdown(nextPath);
            const text = await renderedBlob.text();
            if (signal?.aborted)
                return null;
            setBlob(null);
            setContent(text);
            return text;
        }
        catch (refreshError) {
            if (signal?.aborted)
                return null;
            setError(normalizeError(refreshError, "Failed to load file preview."));
            setContent(null);
            setBlob(null);
            return null;
        }
        finally {
            if (!signal?.aborted)
                setIsLoading(false);
        }
    }, [artifact, client, enabled, mode, podId, trimmedPath]);
    useEffect(() => {
        if (!isEnabled) {
            setContent(null);
            setBlob(null);
            setError(null);
            setIsLoading(false);
            return;
        }
        if (!autoLoad)
            return;
        const controller = new AbortController();
        void refresh({}, controller.signal);
        return () => controller.abort();
    }, [autoLoad, isEnabled, refresh]);
    return useMemo(() => ({
        content,
        blob,
        isLoading,
        error,
        refresh,
    }), [blob, content, error, isLoading, refresh]);
}
